#!/bin/bash

# Log Rotation Script - Secure Implementation
# Archives log files from /var/log to /archive

set -euo pipefail

LOGDIR="/var/log"
ARCHIVEDIR="/archive"

if [ $# -lt 1 ]; then
    echo "Usage: $0 <logfile_relative_path>"
    echo "Example: $0 app/access.log"
    exit 1
fi

LOGFILE="$1"

# --- Security Validations ---

# Reject empty input
if [ -z "$LOGFILE" ]; then
    echo "ERROR: Log filename cannot be empty."
    exit 1
fi

# Reject null bytes (could be used to truncate strings in some contexts)
if [[ "$LOGFILE" == *$'\0'* ]]; then
    echo "ERROR: Invalid characters in filename."
    exit 1
fi

# Reject path traversal sequences before resolving
# This catches obvious malicious input early
if [[ "$LOGFILE" == ../* ]] || [[ "$LOGFILE" == */../* ]] || [[ "$LOGFILE" == */.. ]] || [[ "$LOGFILE" == ".." ]]; then
    echo "ERROR: Path traversal sequences ('..') are not allowed."
    exit 1
fi

# Reject absolute paths - input must be relative to /var/log
if [[ "$LOGFILE" == /* ]]; then
    echo "ERROR: Absolute paths are not allowed. Provide a path relative to $LOGDIR."
    exit 1
fi

# Construct the full source path
SOURCE_PATH="$LOGDIR/$LOGFILE"

# Verify the source file exists before attempting to resolve
if [ ! -e "$SOURCE_PATH" ]; then
    echo "ERROR: Log file does not exist: $SOURCE_PATH"
    exit 1
fi

# Resolve to canonical (real) path to defeat any traversal via symlinks or '..'
REAL_SOURCE="$(realpath "$SOURCE_PATH")"

# Verify the resolved path is still within /var/log
# This is the critical security check that prevents path traversal
if [[ "$REAL_SOURCE" != "$LOGDIR"/* ]]; then
    echo "ERROR: Resolved path '$REAL_SOURCE' is outside of $LOGDIR. Possible path traversal attempt."
    exit 1
fi

# Verify it's a regular file (not a directory, device, socket, etc.)
if [ ! -f "$REAL_SOURCE" ]; then
    echo "ERROR: '$REAL_SOURCE' is not a regular file."
    exit 1
fi

# --- Prepare Archive ---

# Create a timestamped archive filename to avoid overwriting previous archives
TIMESTAMP="$(date +%Y%m%d_%H%M%S)"
ARCHIVE_SUBPATH="${LOGFILE%.log}_${TIMESTAMP}.log"
# Handle files without .log extension
if [[ "$LOGFILE" != *.log ]]; then
    ARCHIVE_SUBPATH="${LOGFILE}_${TIMESTAMP}"
fi

DEST_PATH="$ARCHIVEDIR/$ARCHIVE_SUBPATH"

# Create the archive subdirectory structure if needed (for nested paths)
DEST_DIR="$(dirname "$DEST_PATH")"
if [ ! -d "$DEST_DIR" ]; then
    mkdir -p "$DEST_DIR"
    echo "Created archive directory: $DEST_DIR"
fi

# Verify archive directory is where we expect (defend against symlink attacks on archive dir)
REAL_DEST_DIR="$(realpath "$DEST_DIR")"
if [[ "$REAL_DEST_DIR" != "$ARCHIVEDIR"* ]]; then
    echo "ERROR: Archive directory resolved outside expected location."
    exit 1
fi

# --- Perform the Archive ---

cp "$REAL_SOURCE" "$DEST_PATH"

if [ $? -eq 0 ]; then
    echo "SUCCESS: Archived '$REAL_SOURCE' -> '$DEST_PATH'"

    # Truncate the original log file (preserve file permissions and ownership)
    # This is standard log rotation behavior
    truncate -s 0 "$REAL_SOURCE"
    echo "Truncated original log file: $REAL_SOURCE"
else
    echo "ERROR: Failed to archive '$REAL_SOURCE'."
    exit 1
fi

